// ============================================================
// Code: Nach Empfaenger aufteilen (v2 – komplexe Routing-Logik)
// Ersetzt: "Code: Nach Kunden aufteilen"
//
// WICHTIG: Dieser Node gibt pro Termin MEHRERE Items aus:
//   - 1 Item pro direktem Kunden-Empfänger (Logik a)
//   - 1 Item pro Gruppen-Empfänger (Logik b/c – wird später aufgelöst)
//
// Die ActiveProject-Prüfung für Gruppenmitglieder erfolgt in einem
// NACHGELAGERTEN Node ("Code: Gruppen-Mitglieder auflösen"), weil
// dafür Notion-API-Calls pro Mitglied nötig sind.
// ============================================================

var items = $input.all();
var today = new Date();
today.setHours(0, 0, 0, 0);

// Ergebnis-Map: empfaengerKey → { empfaengerPageId, empfaengerTyp, termine[] }
// empfaengerKey = pageId für Eindeutigkeit
var empfaengerMap = {};

function addTermin(pageId, typ, termin) {
  if (!empfaengerMap[pageId]) {
    empfaengerMap[pageId] = {
      empfaengerPageId: pageId,
      empfaengerTyp: typ,
      termine: []
    };
  }
  // Duplikat-Schutz: gleicher Termin nicht zweimal hinzufügen
  var exists = empfaengerMap[pageId].termine.some(function(t) {
    return t.datumIso === termin.datumIso && t.titel === termin.titel;
  });
  if (!exists) {
    empfaengerMap[pageId].termine.push(termin);
  }
}

for (var i = 0; i < items.length; i++) {
  var props = items[i].json;

  // --- Datum prüfen ---
  var datumObj = props.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start)                               { datumRaw = datumObj.start; }
  else if (typeof datumObj === 'string' && datumObj.length >= 10) { datumRaw = datumObj; }
  if (!datumRaw) continue;

  var terminDate = new Date(datumRaw.substring(0, 10));
  if (terminDate < today) continue;

  // --- Termin-Felder ---
  var titel    = props.property_titel || props.name || 'Kein Titel';
  var ort      = props.property_ort || '';
  var datumIso = datumRaw.substring(0, 10);
  var dp       = datumIso.split('-');
  var datumStr = dp[2] + '.' + dp[1] + '.' + dp[0];
  var uhrzeitStr = '';
  var tIdx = datumRaw.indexOf('T');
  if (tIdx !== -1) { uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6); }

  var termin = {
    datumIso:   datumIso,
    datumStr:   datumStr,
    uhrzeitStr: uhrzeitStr,
    titel:      titel,
    ort:        ort
  };

  // --- Direkte Kunden aus DB Termine (Logik a) ---
  // Diese Kunden erhalten den Termin immer direkt,
  // unabhängig von Gruppen-Mitgliedschaft
  var kundenRaw  = props.property_kunden || [];
  var kundenIds  = Array.isArray(kundenRaw) ? kundenRaw : [kundenRaw];
  for (var j = 0; j < kundenIds.length; j++) {
    if (!kundenIds[j]) continue;
    addTermin(kundenIds[j], 'individuell', termin);
  }

  // --- Gruppen aus DB Termine (Logik b/c) ---
  // Gruppen erhalten den Termin immer.
  // Ob Mitglieder zusätzlich individuell informiert werden,
  // entscheidet der nachgelagerte Node anhand von ActiveProject.
  var gruppenRaw = props.property_gruppen || [];
  var gruppenIds = Array.isArray(gruppenRaw) ? gruppenRaw : [gruppenRaw];
  for (var k = 0; k < gruppenIds.length; k++) {
    if (!gruppenIds[k]) continue;
    addTermin(gruppenIds[k], 'gruppe', termin);
  }
}

// --- Ergebnis aufbauen, Termine sortieren ---
// Alle verfügbaren Notion-Property-Keys für Diagnose (erste Iteration)
var debugPropKeys = items.length > 0
  ? Object.keys(items[0].json).filter(function(k){ return k.startsWith('property_'); }).join(', ')
  : 'keine_items';

var result = [];
var keys = Object.keys(empfaengerMap);
for (var ki = 0; ki < keys.length; ki++) {
  var entry = empfaengerMap[keys[ki]];
  entry.termine.sort(function(a, b) {
    return a.datumIso < b.datumIso ? -1 : a.datumIso > b.datumIso ? 1 : 0;
  });
  result.push({ json: {
    empfaengerPageId:       entry.empfaengerPageId,
    empfaengerTyp:          entry.empfaengerTyp,
    termine:                entry.termine,
    _debug_terminCount:     entry.termine.length,
    _debug_notionPropKeys:  debugPropKeys
  }});
}
return result;

// ============================================================
// Code: Set Empfaengerdaten (v2)
// Läuft nach: Notion: Kundendaten holen (direkte Kunden, Logik a)
// Zweck: Liest confluencePageId + spaceKey für direkte Kunden
//        (Gruppen und Mitglieder haben ihre Daten bereits)
//
// Guard 2: SpaceKey-Präfix gegen empfaengerTyp prüfen
// ============================================================

var loopItem   = $('Loop: Ein Kunde pro Durchlauf').item.json;
var notionData = $json;

var confluencePageId = notionData.property_confluence_page_i_d
  || notionData.property_confluence_page_id || '';
var spaceKey = notionData.property_confluence_space_key || '';
var termine  = loopItem.termine || [];

return {
  json: {
    empfaengerPageId: loopItem.empfaengerPageId,
    empfaengerTyp:    'individuell',
    confluencePageId: confluencePageId,
    spaceKey:         spaceKey,
    termine:          termine
  }
};

// Tabelle im 'Naechste Termine' Panel komplett neu aufbauen.
// Alle aktuellen Termine des Kunden kommen aus dem Loop-Item (nicht aus dem HTML).
// Kein HTML-Kommentar-Tracking noetig.
var page = $json;
var loopItem = $('Loop: Ein Kunde pro Durchlauf').item.json;
var termine = loopItem.termine || [];
// Fallback: vorgelagerte Nodes (falls Loop-Pairing fehlschlägt)
if (termine.length === 0) {
  try { var _t1 = $('Code: Gruppen-PageId setzen').item.json.termine; if (Array.isArray(_t1) && _t1.length > 0) termine = _t1; } catch(e) {}
}
if (termine.length === 0) {
  try { var _t2 = $('Set: Kundendaten').item.json.termine; if (Array.isArray(_t2) && _t2.length > 0) termine = _t2; } catch(e) {}
}
if (termine.length === 0) {
  try { var _t3 = $('Code: ActiveProject filtern').item.json.termine; if (Array.isArray(_t3) && _t3.length > 0) termine = _t3; } catch(e) {}
}

var esc = function(s) { return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); };

var pageId = page.id || '';
var pageTitle = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value) ? page.body.storage.value : '';

// Alle <ac:rich-text-body> Abschnitte sammeln
var rtbOpen = '<ac:rich-text-body>';
var rtbClose = '</ac:rich-text-body>';
var allSections = [];
var sp = 0;
while (true) {
  var oi = html.indexOf(rtbOpen, sp);
  if (oi === -1) break;
  var s = oi + rtbOpen.length;
  var e = html.indexOf(rtbClose, s);
  if (e === -1) break;
  allSections.push({ start: s, end: e });
  sp = e + rtbClose.length;
}

// Titel suchen (mehrere Encodings)
var panelTitles = ['N\u00e4chste Termine', 'N&auml;chste Termine', 'N&#228;chste Termine', 'N&#xE4;chste Termine', 'N&#xe4;chste Termine', 'Termine'];
var titleIdx = -1;
for (var ti = 0; ti < panelTitles.length; ti++) {
  titleIdx = html.indexOf(panelTitles[ti]);
  if (titleIdx !== -1) break;
}

var bodyStart = -1;
var bodyEnd = -1;

// Methode 1a: Section die titleIdx ENTHAELT (Titel ist Heading im Body)
if (titleIdx !== -1) {
  for (var si = 0; si < allSections.length; si++) {
    if (allSections[si].start <= titleIdx && titleIdx < allSections[si].end) {
      bodyStart = allSections[si].start; bodyEnd = allSections[si].end; break;
    }
  }
}
// Methode 1b: Erste Section NACH titleIdx
if (bodyStart === -1 && titleIdx !== -1) {
  for (var si1b = 0; si1b < allSections.length; si1b++) {
    if (allSections[si1b].start > titleIdx) {
      bodyStart = allSections[si1b].start; bodyEnd = allSections[si1b].end; break;
    }
  }
}
// Methode 2: Section mit Datum+Uhrzeit-Headern (vorhandene Tabelle)
if (bodyStart === -1) {
  for (var si2 = 0; si2 < allSections.length; si2++) {
    var sc2 = html.substring(allSections[si2].start, allSections[si2].end);
    if (sc2.indexOf('>Datum<') !== -1 && sc2.indexOf('>Uhrzeit<') !== -1) {
      bodyStart = allSections[si2].start; bodyEnd = allSections[si2].end; break;
    }
  }
}
// Methode 3: ac:layout-cell das titleIdx enthaelt
if (bodyStart === -1 && titleIdx !== -1) {
  var cellOpen = '<ac:layout-cell>';
  var cellClose = '</ac:layout-cell>';
  var cp = 0;
  while (true) {
    var ci = html.indexOf(cellOpen, cp);
    if (ci === -1) break;
    var cs = ci + cellOpen.length;
    var ce = html.indexOf(cellClose, cs);
    if (ce === -1) break;
    if (cs <= titleIdx && titleIdx < ce) { bodyStart = cs; bodyEnd = ce; break; }
    cp = ce + cellClose.length;
  }
}

if (bodyStart === -1 || bodyEnd === -1) {
  var tIdx2 = html.indexOf('Termine');
  var ctx = tIdx2 !== -1 ? html.substring(Math.max(0, tIdx2 - 200), Math.min(html.length, tIdx2 + 400)) : 'nicht_gefunden';
  throw new Error('Panel nicht gefunden. pageId:' + pageId + ' sections:' + allSections.length + ' titleIdx:' + titleIdx + ' || ' + ctx);
}

// Heading (h1/h2/h3) erhalten, Rest ersetzen
var bodyContent = html.substring(bodyStart, bodyEnd);
var headingPart = '';
var headingTags = ['</h1>', '</h2>', '</h3>'];
for (var ht = 0; ht < headingTags.length; ht++) {
  var hEnd = bodyContent.indexOf(headingTags[ht]);
  if (hEnd !== -1) { headingPart = bodyContent.substring(0, hEnd + headingTags[ht].length); break; }
}

// Tabelle komplett neu aufbauen aus termine[]
var headerRow = '<tr><th>Datum</th><th>Uhrzeit</th><th>Titel</th><th>Ort</th></tr>';
var dataRows = '';
for (var ri = 0; ri < termine.length; ri++) {
  var t = termine[ri];
  dataRows += '<tr><td>' + esc(t.datumStr) + '</td><td>' + esc(t.uhrzeitStr) + '</td><td>' + esc(t.titel) + '</td><td>' + esc(t.ort) + '</td></tr>';
}

var tableHtml = termine.length > 0 ? '<table><tbody>' + headerRow + dataRows + '</tbody></table>' : '';
var newBodyContent = headingPart + tableHtml;

html = html.substring(0, bodyStart) + newBodyContent + html.substring(bodyEnd);

return { json: { pageId: pageId, pageTitle: pageTitle, newVersion: currentVersion + 1, updatedHtml: html } };

var items = $input.all();
var errors = items.filter(function(i) { return i.json._guard_error === true; });

if (errors.length > 0) {
  var errorDetails = errors.map(function(e) {
    return '\u2022 "' + e.json.titel + '" (' + e.json.notionPageId + '): ' + e.json._error_reason;
  }).join('\n');

  return errors.map(function(e) {
    return {
      json: {
        _guard_triggered: true,
        notionPageId: e.json.notionPageId,
        titel: e.json.titel,
        errorReason: e.json._error_reason,
        errorSummary: errorDetails,
        timestamp: new Date().toISOString()
      }
    };
  });
}

return items.filter(function(i) { return !i.json._guard_error; });

// ============================================================
// Code: Gruppen-Mitglieder auflösen (NEU)
// Läuft nach: Notion: Gruppendaten holen
// Zweck: Prüft ActiveProject für alle Gruppenmitglieder
//        und erzeugt zusätzliche individuelle Items (Logik b)
//
// Input ($json): Notion-Daten der Gruppe inkl. DB Kunden Relation
// Input (Loop):  empfaengerTyp='gruppe', termine[], confluencePageId
//
// Output:
//   - 1 Item für den Gruppen-Space (immer)
//   - 0-n Items für individuelle Kunden (nur wenn ActiveProject=true)
//
// WICHTIG: Dieser Node gibt mehrere Items zurück.
//          ActiveProject wird aus den Mitgliedsdaten gelesen,
//          die Notion bereits in der Relation mitliefert.
//          Falls Notion die Relation nicht expanded, muss ein
//          separater "Notion: Mitglied laden"-Node ergänzt werden.
// ============================================================

var loopItem = $('Loop: Ein Kunde pro Durchlauf').item.json;
var gruppenData = $json; // Notion-Daten der Gruppe

// Gruppen-SpaceKey + PageID für Confluence
var gruppenSpaceKey      = gruppenData.property_confluence_space_key || '';
var gruppenConfluencePageId = gruppenData.property_confluence_page_i_d
  || gruppenData.property_confluence_page_id || '';

// Termine aus dem Loop
var termine = loopItem.termine || [];

// Mitglieder der Gruppe: Relation "DB Kunden"
// Notion liefert Relation als Array von Page-IDs
var mitgliederRaw = gruppenData.property_db_kunden || [];
var mitgliederIds = Array.isArray(mitgliederRaw) ? mitgliederRaw : [mitgliederRaw];

// Ergebnis-Items
var result = [];

// 1. Gruppen-Space bekommt den Termin IMMER (Logik b + c)
result.push({
  json: {
    empfaengerPageId:    loopItem.empfaengerPageId,
    empfaengerTyp:       'gruppe',
    confluencePageId:    gruppenConfluencePageId,
    spaceKey:            gruppenSpaceKey,
    termine:             termine,
    _mitgliederZuPruefen: mitgliederIds.filter(Boolean)
  }
});

// 2. Pro Mitglied: ActiveProject prüfen
// Notion expanded Relationen nicht automatisch –
// daher werden Mitglieder-PageIds für den nachgelagerten
// "Notion: Mitglied laden"-Node ausgegeben.
// Der ActiveProject-Check erfolgt in "Code: ActiveProject filtern".
for (var m = 0; m < mitgliederIds.length; m++) {
  var mitgliedId = mitgliederIds[m];
  if (!mitgliedId) continue;
  result.push({
    json: {
      empfaengerPageId:  mitgliedId,
      empfaengerTyp:     'mitglied_check', // Zwischenstatus – wird aufgelöst
      termine:           termine,
      _gruppePageId:     loopItem.empfaengerPageId,
      _gruppeSpaceKey:   gruppenSpaceKey
    }
  });
}

return result;

// ============================================================
// Code: ActiveProject filtern (NEU)
// Läuft nach: Notion: Mitglied laden
// Zweck: Entscheidet anhand ActiveProject ob Mitglied
//        individuell informiert wird (Logik b vs. c)
//
// Logik b) ActiveProject=true  → individuellen Kunden-Space befüllen
// Logik c) ActiveProject=false → kein individueller Space, Item verwerfen
// ============================================================

var mitgliedData = $json;

// ActiveProject Checkbox aus DB Kunden (mehrere mögliche Property-Namen)
var activeProject = mitgliedData.property_active_project
  || mitgliedData.property_activeproject
  || mitgliedData.property_activproject
  || false;

// Kunden-SpaceKey + PageID für Confluence
var kundenSpaceKey         = mitgliedData.property_confluence_space_key || '';
var kundenConfluencePageId = mitgliedData.property_confluence_page_i_d
  || mitgliedData.property_confluence_page_id || '';

// Termine aus dem Loop-Kontext
var loopContext = $('Loop: Ein Kunde pro Durchlauf').item.json;
var termine     = loopContext.termine || [];

// Logik c: ActiveProject=false → Item verwerfen
if (!activeProject) {
  return [];
}

return [{
  json: {
    empfaengerPageId:  mitgliedData.id || '',
    empfaengerTyp:     'individuell',
    confluencePageId:  kundenConfluencePageId,
    spaceKey:          kundenSpaceKey,
    termine:           termine,
    _activeProject:    true
  }
}];

// ============================================================
// Code: Gruppen-PageId setzen (NEU)
// Läuft nach: Confluence: Space-Homepage holen
// Zweck: Extrahiert die Confluence Page ID der Gruppen-Homepage
//        (Gruppen haben keine gespeicherte PageID in Notion – nur Space Key)
//
// Input ($json):  Confluence Spaces-API Response
//                 { homepage: { id: "12345678", title: "..." }, key: "GDtest", ... }
// Input (Loop):   empfaengerTyp='gruppe', spaceKey, termine[]
// ============================================================

var homepageResp = $json;
var gruppenItem  = $('Code: Gruppen-Mitglieder auflösen').item.json;

// Homepage-ID aus Confluence Spaces-Antwort extrahieren
var confluencePageId = '';
if (homepageResp.homepage && homepageResp.homepage.id) {
  confluencePageId = String(homepageResp.homepage.id);
}

if (!confluencePageId) {
  throw new Error(
    'GRUPPEN-FEHLER: Keine Homepage-ID für Space "' + gruppenItem.spaceKey + '" gefunden. ' +
    'Response-Keys: ' + Object.keys(homepageResp).join(', ')
  );
}

return {
  json: {
    empfaengerPageId: gruppenItem.empfaengerPageId,
    empfaengerTyp:    'gruppe',
    confluencePageId: confluencePageId,
    spaceKey:         gruppenItem.spaceKey,
    termine:          gruppenItem.termine || []
  }
};
